queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?system_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:system_id ?cg . ?child a :Systems ; p:system_id ?cg . ?l p:it_specialist_id ?pg . ?parent a :It_Support_Specialists ; p:id ?pg . } GROUP BY ?child }
  ?child p:system_name ?system_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :It_Support_Specialists } }
  FILTER(?nf = ?total)
}

